#include <stdio.h>
#include <stdint.h>
#include <limits.h>

int min(int a, int b) { return a < b ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int C[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &C[i]);
        }
        int P[M], Q[M];
        int A[M][N];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &P[i], &Q[i]);
            for (int j = 0; j < Q[i]; j++) {
                scanf("%d", &A[i][j]);
                A[i][j]--;
            }
        }
        uint64_t dp = (1ULL << N) - 1;
        uint64_t mask;
        int cost;
        for (mask = 0; mask <= dp; mask++) {
            cost = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1ULL << i)) != 0) {
                    cost += C[i];
                }
            }
            for (int i = 0; i < M; i++) {
                uint64_t subset = 0;
                for (int j = 0; j < Q[i]; j++) {
                    subset |= 1ULL << A[i][j];
                }
                if ((mask & subset) == subset) {
                    cost = min(cost, P[i]);
                }
            }
            if (mask == dp) {
                printf("%d\n", cost);
            }
        }
    }
    return 0;
}

